const items = $input.all();

if (!items || items.length === 0 || !items[0].json) {
  throw new Error('No agreement found for the supplied member_agreement_id');
}

const row = items[0].json;
const body = $('Webhook').first().json.body || {};

if (!row.member_agreement_id) {
  throw new Error('member_agreement_id is missing from the loaded agreement row');
}

if (row.status === 'canceled') {
  throw new Error(`Agreement ${row.member_agreement_id} is already canceled.`);
}

if (row.signature_method !== 'documenso') {
  throw new Error(`Only Documenso agreements can be canceled by this workflow. Current signature_method: ${row.signature_method}`);
}

if (row.status !== 'pending_signature') {
  throw new Error(`Only pending_signature Documenso agreements can be canceled. Current status: ${row.status}`);
}

if (!row.documenso_document_id) {
  throw new Error('Agreement is missing documenso_document_id; there is no Documenso envelope to cancel.');
}

const reason = String(body.reason ?? row.review_notes ?? '').trim();
if (!reason) {
  throw new Error('Cancel reason is required. Populate Review/Cancel Notes before canceling.');
}

const actorMemberId = String(body.actor_member_id ?? '').trim();
const actorEmail = String(body.actor_email ?? '').trim().toLowerCase();

return [{
  json: {
    member_agreement_id: row.member_agreement_id,
    member_id: row.member_id,
    actor_member_id: actorMemberId,
    actor_email: actorEmail,
    reason,
    reason_b64: Buffer.from(reason, 'utf8').toString('base64'),
    documenso_document_id: row.documenso_document_id,
    documenso_external_id: row.documenso_external_id || null,
    payload: {
      envelopeId: row.documenso_document_id
    }
  }
}];

const cancel = $('Validate Cancelability').first().json;
const full = $json;
const responseForDb = {
  statusCode: full.statusCode ?? full.status ?? null,
  body: full.body ?? full
};

return [{
  json: {
    ...cancel,
    documenso_cancel_response_b64: Buffer
      .from(JSON.stringify(responseForDb), 'utf8')
      .toString('base64')
  }
}];
